import React, { createContext, useState, useContext, useEffect } from 'react';

const ProductContext = createContext();

export const ProductProvider = ({ children }) => {
  const [products, setProducts] = useState(() => {
    const savedProducts = localStorage.getItem('products');
    return savedProducts ? JSON.parse(savedProducts) : [
      { id: 1, name: 'Mevalar toplami', price: 45000, stock: 50, image: 'https://images.unsplash.com/photo-1610832958506-aa56368176cf?auto=format&fit=crop&q=80&w=400' },
      { id: 2, name: 'Sabzavotlar seti', price: 32000, stock: 120, image: 'https://images.unsplash.com/photo-1566385101042-1a0aa0c12e8c?auto=format&fit=crop&q=80&w=400' },
      { id: 3, name: 'Sut mahsulotlari', price: 12500, stock: 45, image: 'https://images.unsplash.com/photo-1550583724-125581fe2f8a?auto=format&fit=crop&q=80&w=400' },
    ];
  });

  const [staff, setStaff] = useState(() => {
    const savedStaff = localStorage.getItem('staff');
    return savedStaff ? JSON.parse(savedStaff) : [];
  });

  const [user, setUser] = useState(() => {
    const savedUser = localStorage.getItem('user');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  useEffect(() => {
    localStorage.setItem('products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('staff', JSON.stringify(staff));
  }, [staff]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('user', JSON.stringify(user));
    } else {
      localStorage.removeItem('user');
    }
  }, [user]);

  const addProduct = (newProduct) => {
    setProducts((prev) => [...prev, { ...newProduct, id: Date.now() }]);
  };

  const addStaff = (email, password) => {
    const exists = staff.find(s => s.email === email);
    if (exists) {
      alert('Bu email bilan xodim allaqachon mavjud!');
      return false;
    }
    const newStaff = { id: Date.now(), email, password, role: 'staff' };
    setStaff([...staff, newStaff]);
    return true;
  };

  const deleteStaff = (id) => {
    setStaff(staff.filter(s => s.id !== id));
  };

  const login = (email, password) => {
    // Admin check (hardcoded for example, or could be in a separate admin state)
    if (email === 'admin@gmail.com' && password === 'admin123') {
      const adminUser = { email, role: 'admin' };
      setUser(adminUser);
      return adminUser;
    }

    // Staff check
    const foundStaff = staff.find(s => s.email === email && s.password === password);
    if (foundStaff) {
      const staffUser = { email: foundStaff.email, role: 'staff' };
      setUser(staffUser);
      return staffUser;
    }

    return null;
  };

  const logout = () => {
    setUser(null);
  };

  return (
    <ProductContext.Provider value={{ 
      products, 
      addProduct, 
      staff, 
      addStaff, 
      deleteStaff, 
      user, 
      login, 
      logout 
    }}>
      {children}
    </ProductContext.Provider>
  );
};

export const useProducts = () => useContext(ProductContext);
